1639 void LoopVectorizationPlanner::updateLoopMetadataAndProfileInfo(
1640     Loop *VectorLoop, VPBasicBlock *HeaderVPBB, const VPlan &Plan,
1641     bool VectorizingEpilogue, MDNode *OrigLoopID,
1642     std::optional<unsigned> OrigAverageTripCount,
1643     unsigned OrigLoopInvocationWeight, unsigned EstimatedVFxUF,
1644     bool DisableRuntimeUnroll) {
1645   // Update the metadata of the scalar loop. Skip the update when vectorizing
1646   // the epilogue loop to ensure it is updated only once. Also skip the update
1647   // when the scalar loop became unreachable.
1648   if (Plan.getScalarPreheader()->hasPredecessors() && !VectorizingEpilogue) {
1649     std::optional<MDNode *> RemainderLoopID =
1650         makeFollowupLoopID(OrigLoopID, {LLVMLoopVectorizeFollowupAll,
1651                                         LLVMLoopVectorizeFollowupEpilogue});
1652     if (RemainderLoopID) {
1653       OrigLoop->setLoopID(*RemainderLoopID);
1654     } else {
1655       if (DisableRuntimeUnroll)
1656         addRuntimeUnrollDisableMetaData(OrigLoop);
1657 
1658       LoopVectorizeHints Hints(OrigLoop, true, *ORE);
1659       Hints.setAlreadyVectorized();
1660     }
1661   }
1662 
1663   if (!VectorLoop)
1664     return;
1665 
1666   if (std::optional<MDNode *> VectorizedLoopID = makeFollowupLoopID(
1667           OrigLoopID, {LLVMLoopVectorizeFollowupAll,
1668                        LLVMLoopVectorizeFollowupVectorized})) {
1669     VectorLoop->setLoopID(*VectorizedLoopID);
1670   } else {
1671     // Keep all loop hints from the original loop on the vector loop (we'll
1672     // replace the vectorizer-specific hints below).
1673     if (OrigLoopID)
1674       VectorLoop->setLoopID(OrigLoopID);
1675 
1676     if (!VectorizingEpilogue) {
1677       LoopVectorizeHints Hints(VectorLoop, true, *ORE);
1678       Hints.setAlreadyVectorized();
1679     }
1680   }
1681   TargetTransformInfo::UnrollingPreferences UP;
1682   TTI.getUnrollingPreferences(VectorLoop, *PSE.getSE(), UP, ORE);
1683   if (!UP.UnrollVectorizedLoop || VectorizingEpilogue)
1684     addRuntimeUnrollDisableMetaData(VectorLoop);
1685 
1686   // Set/update profile weights for the vector and remainder loops as original
1687   // loop iterations are now distributed among them. Note that original loop
1688   // becomes the scalar remainder loop after vectorization.
1689   //
1690   // For cases like foldTailByMasking() and requiresScalarEpiloque() we may
1691   // end up getting slightly roughened result but that should be OK since
1692   // profile is not inherently precise anyway. Note also possible bypass of
1693   // vector code caused by legality checks is ignored, assigning all the weight
1694   // to the vector loop, optimistically.
1695   //
1696   // For scalable vectorization we can't know at compile time how many
1697   // iterations of the loop are handled in one vector iteration, so instead
1698   // use the value of vscale used for tuning.
1699   unsigned AverageVectorTripCount = 0;
1700   unsigned RemainderAverageTripCount = 0;
1701   auto EC = VectorLoop->getLoopPreheader()->getParent()->getEntryCount();
1702   auto IsProfiled = EC && EC->getCount();
1703   if (!OrigAverageTripCount) {
1704     if (!IsProfiled)
1705       return;
1706     auto &SE = *PSE.getSE();
1707     AverageVectorTripCount = SE.getSmallConstantTripCount(VectorLoop);
1708     if (ProfcheckDisableMetadataFixes || !AverageVectorTripCount)
1709       return;
1710     if (Plan.getScalarPreheader()->hasPredecessors())
1711       RemainderAverageTripCount =
1712           SE.getSmallConstantTripCount(OrigLoop) % EstimatedVFxUF;
1713     // Setting to 1 should be sufficient to generate the correct branch weights.
1714     OrigLoopInvocationWeight = 1;
1715   } else {
1716     // Calculate number of iterations in unrolled loop.
1717     AverageVectorTripCount = *OrigAverageTripCount / EstimatedVFxUF;
1718     // Calculate number of iterations for remainder loop.
1719     RemainderAverageTripCount = *OrigAverageTripCount % EstimatedVFxUF;
1720   }
1721   if (HeaderVPBB) {
1722     setLoopEstimatedTripCount(VectorLoop, AverageVectorTripCount,
1723                               OrigLoopInvocationWeight);
1724   }
1725 
1726   if (Plan.getScalarPreheader()->hasPredecessors()) {
1727     setLoopEstimatedTripCount(OrigLoop, RemainderAverageTripCount,
1728                               OrigLoopInvocationWeight);
1729   }
1730 }
