1764 InstructionCost VPCostContext::getScalarizationOverhead(
1765     Type *ResultTy, ArrayRef<const VPValue *> Operands, ElementCount VF,
1766     bool AlwaysIncludeReplicatingR) {
1767   if (VF.isScalar())
1768     return 0;
1769 
1770   assert(!VF.isScalable() &&
1771          "Scalarization overhead not supported for scalable vectors");
1772 
1773   InstructionCost ScalarizationCost = 0;
1774   // Compute the cost of scalarizing the result if needed.
1775   if (!ResultTy->isVoidTy()) {
1776     for (Type *VectorTy :
1777          to_vector(getContainedTypes(toVectorizedTy(ResultTy, VF)))) {
1778       ScalarizationCost += TTI.getScalarizationOverhead(
1779           cast<VectorType>(VectorTy), APInt::getAllOnes(VF.getFixedValue()),
1780           /*Insert=*/true,
1781           /*Extract=*/false, CostKind);
1782     }
1783   }
1784   // Compute the cost of scalarizing the operands, skipping ones that do not
1785   // require extraction/scalarization and do not incur any overhead.
1786   SmallPtrSet<const VPValue *, 4> UniqueOperands;
1787   SmallVector<Type *> Tys;
1788   for (auto *Op : Operands) {
1789     if (isa<VPIRValue>(Op) ||
1790         (!AlwaysIncludeReplicatingR &&
1791          isa<VPReplicateRecipe, VPPredInstPHIRecipe>(Op)) ||
1792         (isa<VPReplicateRecipe>(Op) &&
1793          cast<VPReplicateRecipe>(Op)->getOpcode() == Instruction::Load) ||
1794         !UniqueOperands.insert(Op).second)
1795       continue;
1796     Tys.push_back(toVectorizedTy(Types.inferScalarType(Op), VF));
1797   }
1798   return ScalarizationCost +
1799          TTI.getOperandsScalarizationOverhead(Tys, CostKind);
